   124→// ── Object ID → interaction particle type ──
   125→function getInteractParticleType(char) {
   126→  const id = char.targetObjectId;
   127→  if (!id) return 'interact_sparkle';
   128→  if (id.includes('espresso') || id.includes('coffee')) return 'steam';
   129→  if (id.includes('stove')) return 'oven_embers';
   130→  if (id.includes('sink')) return 'water_drops';
   131→  if (id.includes('easel')) return 'paint_splatter';
   132→  if (id.includes('book')) return 'paper_flutter';
   133→  return 'interact_sparkle';
   134→}
