// ═══════════════════════════════════════════════════════════
// Character System — Movement, Perception, A* Pathfinding
// ═══════════════════════════════════════════════════════════
//
// Characters have: id, name, personality, position, action state,
// mood, energy, facing direction. They move between tiles using
// A* pathfinding on the walkable tilemap.
//
// Walk animation alternates walk1/walk2 sprites while moving.
// Perception system returns nearby objects and characters within radius.

import { MAP, T, MAP_COLS, MAP_ROWS, TILE_SIZE } from './tilemap.js';

// ── Walkable tiles (everything except walls, fences, water) ──
const UNWALKABLE = new Set([T.WALL, T.WALL_TOP, T.COUNTER, T.COUNTER_L, T.COUNTER_R, T.WINDOW]);

export function isWalkable(tx, ty) {
  if (tx < 0 || tx >= MAP_COLS || ty < 0 || ty >= MAP_ROWS) return false;
  return !UNWALKABLE.has(MAP[ty][tx]);
}

// ── A* Pathfinding ──
// Returns array of {tx, ty} waypoints (excludes start, includes goal),
// or null if no path found. Returns [] if already at goal.

const NEIGHBORS = [[0, -1], [0, 1], [-1, 0], [1, 0]];

export function findPath(sx, sy, gx, gy) {
  if (!isWalkable(gx, gy)) return null;

  const startKey = sy * MAP_COLS + sx;
  const goalKey = gy * MAP_COLS + gx;
  if (startKey === goalKey) return [];

  const open = [startKey];
  const cameFrom = new Map();
  const gScore = new Map([[startKey, 0]]);
  const fScore = new Map([[startKey, Math.abs(sx - gx) + Math.abs(sy - gy)]]);
  const closed = new Set();

  while (open.length > 0) {
    // Find node with lowest fScore
    let bestIdx = 0;
    let bestF = fScore.get(open[0]) ?? Infinity;
    for (let i = 1; i < open.length; i++) {
      const f = fScore.get(open[i]) ?? Infinity;
      if (f < bestF) { bestF = f; bestIdx = i; }
    }

    const current = open[bestIdx];
    if (current === goalKey) {
      const path = [];
      let c = current;
      while (cameFrom.has(c)) {
        path.unshift({ tx: c % MAP_COLS, ty: Math.floor(c / MAP_COLS) });
        c = cameFrom.get(c);
      }
      return path;
    }

    open.splice(bestIdx, 1);
    closed.add(current);

    const cx = current % MAP_COLS;
    const cy = Math.floor(current / MAP_COLS);

    for (const [dx, dy] of NEIGHBORS) {
      const nx = cx + dx;
      const ny = cy + dy;
      if (!isWalkable(nx, ny)) continue;

      const nKey = ny * MAP_COLS + nx;
      if (closed.has(nKey)) continue;

      const tentG = (gScore.get(current) ?? Infinity) + 1;
      if (tentG < (gScore.get(nKey) ?? Infinity)) {
        cameFrom.set(nKey, current);
        gScore.set(nKey, tentG);
        fScore.set(nKey, tentG + Math.abs(nx - gx) + Math.abs(ny - gy));
        if (!open.includes(nKey)) open.push(nKey);
      }
    }
  }

  return null; // no path
}

// ── Find walkable tile adjacent to an object (for interaction) ──
export function findInteractTile(objPosition) {
  const { tx, ty, tw = 1, th = 1 } = objPosition;
  const candidates = [];

  for (let x = tx - 1; x <= tx + tw; x++) {
    if (isWalkable(x, ty - 1)) candidates.push({ tx: x, ty: ty - 1 });
    if (isWalkable(x, ty + th)) candidates.push({ tx: x, ty: ty + th });
  }
  for (let y = ty; y < ty + th; y++) {
    if (isWalkable(tx - 1, y)) candidates.push({ tx: tx - 1, ty: y });
    if (isWalkable(tx + tw, y)) candidates.push({ tx: tx + tw, ty: y });
  }

  if (candidates.length === 0) return null;
  return candidates[Math.floor(Math.random() * candidates.length)];
}

// ── Character class ──

export class Character {
  constructor(def) {
    this.id = def.id;
    this.name = def.name;
    this.personality = def.personality;
    this.tx = def.tx;
    this.ty = def.ty;
    this.homeSector = def.sector;
    this.energy = 100;
    this.facing = 'down'; // up | down | left | right
    this.action = 'idle'; // idle | walking | interacting
    this.colors = def.colors; // fallback render colors

    // Movement
    this.path = [];          // waypoints to follow
    this.moveProgress = 0;   // 0–1 progress toward next waypoint
    this.moveSpeed = 2.0;    // tiles per second
    this.prevTx = def.tx;
    this.prevTy = def.ty;

    // Walk animation (4-frame cycle: walk1→walk2→walk3→walk4)
    this.walkFrame = 0;      // 0–3 → walk1/walk2/walk3/walk4
    this.walkTimer = 0;
    this.walkFrameMs = 200;  // ms between frame advances

    // Wander AI
    this.targetObjectId = null;
    this.wanderCooldown = 2000 + Math.random() * 5000; // start soon
    this.interactTimer = 0;

    // Interaction tracking
    this.lastObjectId = null;
    this.pendingAction = 'use';
    this.interactAnim = null;    // 'reading' | 'sit' | 'phone' | null (uses idle when null)
    this.targetCharId = null;   // ID of a character to face toward upon arrival

    // Mood system
    this.mood = 'content';       // happy | content | neutral | upset
    this.moodTimer = 0;          // ms until mood resets to content
  }

  /** Sprite key for the current animation frame. */
  get spriteKey() {
    if (this.action === 'walking') {
      return `${this.id}_walk${this.walkFrame + 1}`;
    }
    if (this.action === 'interacting' && this.interactAnim) {
      return `${this.id}_${this.interactAnim}`;
    }
    return `${this.id}_idle`;
  }

  get moodEmoji() {
    switch (this.mood) {
      case 'happy': return '😊';
      case 'content': return '😌';
      case 'upset': return '😤';
      default: return null;
    }
  }

  /** Pixel X position (interpolated between tiles for smooth movement). */
  get px() {
    if (this.path.length === 0) return this.tx * TILE_SIZE;
    const next = this.path[0];
    return (this.prevTx + (next.tx - this.prevTx) * this.moveProgress) * TILE_SIZE;
  }

  /** Pixel Y position (interpolated between tiles for smooth movement). */
  get py() {
    if (this.path.length === 0) return this.ty * TILE_SIZE;
    const next = this.path[0];
    return (this.prevTy + (next.ty - this.prevTy) * this.moveProgress) * TILE_SIZE;
  }

  /** Start moving toward a goal tile. Returns true if a path was found. */
  moveTo(goalTx, goalTy) {
    const path = findPath(Math.round(this.tx), Math.round(this.ty), goalTx, goalTy);
    if (path && path.length > 0) {
      this.path = path;
      this.prevTx = Math.round(this.tx);
      this.prevTy = Math.round(this.ty);
      this.moveProgress = 0;
      this.action = 'walking';
      this._updateFacing(path[0].tx - this.prevTx, path[0].ty - this.prevTy);
      return true;
    }
    return false;
  }

  /** Per-frame update: advance position and animation. */
  update(deltaMs) {
    if (this.action === 'walking' && this.path.length > 0) {
      // Walk animation cycle (4 frames)
      this.walkTimer += deltaMs;
      if (this.walkTimer >= this.walkFrameMs) {
        this.walkTimer -= this.walkFrameMs;
        this.walkFrame = (this.walkFrame + 1) % 4;
      }

      // Advance position along path
      const tileDurationMs = 1000 / this.moveSpeed;
      this.moveProgress += deltaMs / tileDurationMs;

      while (this.moveProgress >= 1 && this.path.length > 0) {
        this.moveProgress -= 1;
        const arrived = this.path.shift();
        this.tx = arrived.tx;
        this.ty = arrived.ty;
        this.prevTx = arrived.tx;
        this.prevTy = arrived.ty;

        if (this.path.length > 0) {
          this._updateFacing(this.path[0].tx - this.tx, this.path[0].ty - this.ty);
        }
      }

      // Arrived at destination
      if (this.path.length === 0) {
        this.moveProgress = 0;
        this.action = 'idle';
      }
    } else if (this.action === 'interacting') {
      this.interactTimer -= deltaMs;
      if (this.interactTimer <= 0) {
        this.action = 'idle';
        this.targetObjectId = null;
        this.interactAnim = null;
      }
    }

    // Decay mood back to content
    if (this.moodTimer > 0) {
      this.moodTimer -= deltaMs;
      if (this.moodTimer <= 0) {
        this.mood = 'content';
        this.moodTimer = 0;
      }
    }
  }

  _updateFacing(dx, dy) {
    if (dx > 0) this.facing = 'right';
    else if (dx < 0) this.facing = 'left';
    else if (dy > 0) this.facing = 'down';
    else if (dy < 0) this.facing = 'up';
  }

  /** Enter interaction state (after arriving at an object).
   *  @param {string} objectId - ID of the object being interacted with.
   *  @param {string|null} anim - Animation to play: 'reading' | 'sit' | 'phone' | null.
   */
  startInteraction(objectId, anim = null) {
    this.action = 'interacting';
    this.targetObjectId = objectId;
    this.lastObjectId = objectId;
    this.interactTimer = 2000;
    this.interactAnim = anim;
  }

  setMood(mood, durationMs = 15000) {
    this.mood = mood;
    this.moodTimer = durationMs;
  }

  /** Get nearby objects and characters within Manhattan distance radius. */
  getPerception(objects, characters, radius = 5) {
    const nearbyObjects = [];
    const nearbyCharacters = [];

    for (const obj of objects) {
      const dist = Math.abs(obj.position.tx - this.tx) + Math.abs(obj.position.ty - this.ty);
      if (dist <= radius) {
        nearbyObjects.push({
          id: obj.id,
          name: obj.name,
          state: obj.state,
          distance: dist,
          sector: obj.sector,
        });
      }
    }

    for (const char of characters) {
      if (char.id === this.id) continue;
      const dist = Math.abs(char.tx - this.tx) + Math.abs(char.ty - this.ty);
      if (dist <= radius) {
        nearbyCharacters.push({
          id: char.id,
          name: char.name,
          action: char.action,
          distance: dist,
        });
      }
    }

    return { objects: nearbyObjects, characters: nearbyCharacters };
  }
}

// ── Character definitions ──

export const CHARACTER_DEFS = [
  {
    id: 'maple',
    name: 'Maple',
    personality: 'Warm, chatty barista who takes pride in her coffee. Runs the café downstairs.',
    sector: 'cafe',
    tx: 3, ty: 12,
    colors: { body: '#e8a87c', hair: '#d4543b', outfit: '#f5e6cc' },
  },
  {
    id: 'sol',
    name: 'Sol',
    personality: 'Quiet, bookish regular who loves the window seat. Friendly when approached.',
    sector: 'cafe',
    tx: 10, ty: 16,
    colors: { body: '#b5835a', hair: '#2d5e2a', outfit: '#7ab648' },
  },
  {
    id: 'nyx',
    name: 'Nyx',
    personality: 'Creative night owl who lives upstairs. Paints, cooks, and is slightly scatterbrained.',
    sector: 'apartment',
    tx: 3, ty: 4,
    colors: { body: '#c4aed0', hair: '#3a2d5e', outfit: '#1a1a2e' },
  },
];

